
"use server";

import { auth } from "@/lib/firebase";
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut 
} from "firebase/auth";
import { redirect } from 'next/navigation';

export async function signUpWithEmailPassword(prevState: any, formData: FormData) {
  const email = formData.get("email") as string;
  const password = formData.get("password") as string;

  if (!email || !password) {
    return { message: "Email and password are required.", success: false };
  }

  try {
    await createUserWithEmailAndPassword(auth, email, password);
    // Server actions cannot directly call redirect from 'next/navigation' in the same tick
    // after a state update from Firebase. Client-side redirect after form success is preferred.
    // However, for non-interactive success, you might redirect to a success page or rely on client to redirect.
    // For this example, we'll return a success message.
    // A more robust solution might involve using useRouter on the client after form submission.
     return { message: "Signup successful! Redirecting...", success: true, redirectUrl: "/" };
  } catch (error: any) {
    return { message: error.message || "Failed to sign up.", success: false };
  }
}

export async function signInWithEmailPassword(prevState: any, formData: FormData) {
  const email = formData.get("email") as string;
  const password = formData.get("password") as string;

  if (!email || !password) {
    return { message: "Email and password are required.", success: false };
  }

  try {
    await signInWithEmailAndPassword(auth, email, password);
    return { message: "Login successful! Redirecting...", success: true, redirectUrl: "/" };
  } catch (error: any) {
    return { message: error.message || "Failed to sign in.", success: false };
  }
}

export async function logout() {
  try {
    await signOut(auth);
    // In server actions, redirect needs to be handled carefully.
    // It's often better to trigger a client-side redirect after the action completes.
    // For now, this will attempt a server-side redirect.
  } catch (error: any) {
    console.error("Logout failed:", error);
    // Potentially return an error state if needed, though logout failure is rare
  }
  redirect('/login'); // This will trigger a page reload
}
